    reg [24:0] a_mant_norm, b_mant_norm;
    reg a_zero, b_zero, a_inf, b_inf, a_nan, b_nan;
    reg [10:0] exp_sum;
    reg [50:0] product_extended;
    reg [9:0] z_exp_temp;
    reg z_sign_temp;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            counter <= 3'b000;
            z <= 32'b0;
            a_mantissa <= 24'b0;
            b_mantissa <= 24'b0;
            z_mantissa <= 24'b0;
            a_exponent <= 10'b0;
            b_exponent <= 10'b0;
            z_exponent <= 10'b0;
            a_sign <= 1'b0;
            b_sign <= 1'b0;
            z_sign <= 1'b0;
            product <= 50'b0;
            guard_bit <= 1'b0;
            round_bit <= 1'b0;
            sticky <= 1'b0;
        end else begin
            case (counter)
                3'b000: begin
                    // Extract sign bits
                    a_sign <= a[31];
                    b_sign <= b[31];
                    z_sign_temp <= a[31] ^ b[31];

                    // Extract exponents
                    a_exp_8 <= a[30:23];
                    b_exp_8 <= b[30:23];

                    // Extract mantissas and add implicit leading 1
                    if (a[30:23] == 8'b0) begin
                        a_mant_norm <= {1'b0, a[22:0]};
                        a_zero <= 1'b1;
                    end else begin
                        a_mant_norm <= {1'b1, a[22:0]};
                        a_zero <= 1'b0;
                    end

                    if (b[30:23] == 8'b0) begin
                        b_mant_norm <= {1'b0, b[22:0]};
                        b_zero <= 1'b1;
                    end else begin
                        b_mant_norm <= {1'b1, b[22:0]};
                        b_zero <= 1'b0;
