                        z <= {z_sign_temp, 8'hFF, 23'b0};
                        counter <= 3'b111;
                    end else if (a_zero || b_zero) begin
                        // Zero result
                        z <= {z_sign_temp, 31'b0};
                        counter <= 3'b111;
                    end else begin
                        // Normal multiplication
