                        z_exp_temp <= exp_sum - 10'd127 + 10'd1;
                        guard_bit <= product_extended[0];
                        round_bit <= 1'b0;
                        sticky <= 1'b0;
                    end else begin
                        product <= product_extended[49:0];
                        z_exp_temp <= exp_sum - 10'd127;
                        guard_bit <= product_extended[49];
                        round_bit <= product_extended[48];
                        sticky <= |product_extended[47:0];
                    end
                    counter <= 3'b011;
                end

