    localparam STATE_IDLE = 3'b000;
    localparam STATE_S1   = 3'b001;
    localparam STATE_S2   = 3'b010;
    localparam STATE_S3   = 3'b011;
    localparam STATE_S4   = 3'b100;

    // State register
    reg [2:0] current_state, next_state;

    // Output assignment
    assign sequence_detected = (current_state == STATE_S4);
    assign IDLE = (current_state == STATE_IDLE);
    assign S1 = (current_state == STATE_S1);
    assign S2 = (current_state == STATE_S2);
    assign S3 = (current_state == STATE_S3);
    assign S4 = (current_state == STATE_S4);

    // Sequential logic for state transitions
    always @(posedge clk or negedge reset_n) begin
        if (!reset_n) begin
            current_state <= STATE_IDLE;
        end else begin
            current_state <= next_state;
        end
