module LIFObuffer(
    input [3:0] dataIn,
    input RW,
    input EN,
    input Rst,
    input Clk,
    output EMPTY,
    output FULL,
    output [3:0] dataOut
);

    reg [3:0] stack_mem [0:3];  // Stack memory: 4 entries, 4-bit wide
    reg [2:0] SP;               // Stack pointer (0-3 for valid entries, 4 for empty)
    reg [3:0] dataOut;

    // EMPTY flag: SP == 4 means stack is empty
    assign EMPTY = (SP == 3'd4);

    // FULL flag: SP == 0 means stack is full
    assign FULL = (SP == 3'd0);

    always @(posedge Clk) begin
        if (EN) begin
            if (Rst) begin
                // Reset: clear stack and initialize
                SP <= 3'd4;
                stack_mem[0] <= 4'b0000;
                stack_mem[1] <= 4'b0000;
                stack_mem[2] <= 4'b0000;
                stack_mem[3] <= 4'b0000;
                dataOut <= 4'b0000;
            end
            else begin
                if (~RW) begin
                    // Write operation (push)
                    if (~FULL) begin
                        stack_mem[SP] <= dataIn;
                        SP <= SP - 3'd1;
                    end
                end
                else begin
                    // Read operation (pop)
                    if (~EMPTY) begin
                        dataOut <= stack_mem[SP];
                        stack_mem[SP] <= 4'b0000;
                        SP <= SP + 3'd1;
                    end
                end
            end
        end
    end

endmodule

