    input rst_n,
    input clk,
    input pass_request,
    output [7:0] clock,
    output red,
    output yellow,
    output green
);

    // State parameters
    parameter idle = 2'b00;
    parameter s1_red = 2'b01;
    parameter s2_yellow = 2'b10;
    parameter s3_green = 2'b11;

    // Internal registers
    reg [7:0] cnt;
    reg [1:0] state;
    reg p_red, p_yellow, p_green;

    // State transition logic
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= idle;
        end else begin
            case (state)
                idle: begin
                    p_red <= 1'b0;
                    p_yellow <= 1'b0;
                    p_green <= 1'b0;
                    state <= s1_red;
                end
                s1_red: begin
                    p_red <= 1'b1;
                    p_yellow <= 1'b0;
                    p_green <= 1'b0;
                    if (cnt == 8'b0) begin
                        state <= s3_green;
                    end else begin
                        state <= s1_red;
                    end
                end
                s2_yellow: begin
                    p_red <= 1'b0;
                    p_yellow <= 1'b1;
                    p_green <= 1'b0;
                    if (cnt == 8'b0) begin
                        state <= s1_red;
                    end else begin
                        state <= s2_yellow;
                    end
                end
                s3_green: begin
                    p_red <= 1'b0;
                    p_yellow <= 1'b0;
                    p_green <= 1'b1;
                    if (cnt == 8'b0) begin
                        state <= s2_yellow;
                    end else begin
                        state <= s3_green;
                    end
                end
                default: begin
                    state <= idle;
                end
            endcase
        end
    end

    // Counter logic
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 8'd10;
        end else begin
            if (pass_request && p_green) begin
                cnt <= 8'd10;
            end else if (!p_green && green) begin
                cnt <= 8'd60;
            end else if (!p_yellow && yellow) begin
                cnt <= 8'd5;
            end else if (!p_red && red) begin
                cnt <= 8'd10;
            end else begin
                if (cnt > 8'b0) begin
                    cnt <= cnt - 1'b1;
                end
            end
        end
    end

    // Assign counter to output
    assign clock = cnt;

    // Output assignment
    assign red = p_red;
    assign yellow = p_yellow;
    assign green = p_green;

endmodule

